  1→/**
  2→ * Walking Skeleton: Observer Agent Reality Verification E2E
  3→ *
  4→ * Traces: Story 1, Story 3, Story 4, Story 6
  5→ *
  6→ * These are the minimum viable E2E paths through the observer verification system.
  7→ * Skeleton 1: Task completed -> Observer verifies -> observation created with verdict
  8→ * Skeleton 2: External signal unavailable -> Observer degrades gracefully
  9→ *
 10→ * Together they prove:
 11→ * - A completed task triggers the Observer to create a verification observation
 12→ * - The observation links back to the triggering entity via the observes edge
 13→ * - When external verification signals are unavailable, the system degrades gracefully
 14→ * - The Observer never blocks the original workflow
 15→ *
 16→ * Driving ports:
 17→ *   POST /api/observe/task/:id         (SurrealQL EVENT target)
 18→ *   SurrealDB direct queries           (verification of outcomes)
 19→ */
 20→import { describe, expect, it, beforeAll } from "bun:test";
 21→import {
 22→  setupObserverSuite,
 23→  wireObserverEvents,
 24→  createTaskWithCommit,
 25→  triggerTaskCompletion,
 26→  waitForObservation,
 27→  getWorkspaceObservations,
 28→  setupObserverWorkspace,
 29→} from "./observer-test-kit";
 30→
 31→const getRuntime = setupObserverSuite("observer_walking_skeleton");
 32→
 33→// Wire the SurrealQL EVENTs so they fire http::post to the real test server
 34→beforeAll(async () => {
 35→  const { surreal, port } = getRuntime();
 36→  await wireObserverEvents(surreal, port);
 37→});
 38→
 39→describe("Walking Skeleton: Task completion triggers observer verification", () => {
 40→  // ---------------------------------------------------------------------------
 41→  // Walking Skeleton 1: Task completed -> observation created with verification
 42→  // Story 1 + Story 4 + Story 6 happy path
 43→  // ---------------------------------------------------------------------------
 44→  it("observer creates a verification observation when a task is marked completed", async () => {
 45→    const { baseUrl, surreal } = getRuntime();
 46→
 47→    // Given a workspace with a task linked to a source commit
 48→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "skeleton-verify");
 49→
 50→    const { taskId, sha } = await createTaskWithCommit(
 51→      surreal,
 52→      workspaceId,
 53→      {
 54→        title: "Add input validation to signup form",
 55→        description: "Validate email format and password strength on the signup page",
 56→        status: "in_progress",
 57→        repository: "org/brain",
 58→      },
 59→    );
 60→
 61→    // When the task is marked as completed
 62→    await triggerTaskCompletion(surreal, taskId);
 63→
 64→    // Then the Observer receives the task completion event
 65→    // And creates an observation linked to the task via the observes edge
 66→    const observations = await waitForObservation(surreal, "task", taskId, 30_000);
 67→
 68→    expect(observations.length).toBeGreaterThanOrEqual(1);
 69→
 70→    const obs = observations[0];
 71→    // And the observation records the observer as its source
 72→    expect(obs.source_agent).toBe("observer_agent");
 73→    // And the observation has a verification-related type
 74→    expect(obs.severity).toBeDefined();
 75→    expect(["info", "warning", "conflict"]).toContain(obs.severity);
 76→    // And the observation text describes the verification outcome
 77→    expect(obs.text).toBeTruthy();
 78→  }, 120_000);
 79→
 80→  // ---------------------------------------------------------------------------
 81→  // Walking Skeleton 2: External signal unavailable -> graceful degradation
 82→  // Story 3 happy path
 83→  // ---------------------------------------------------------------------------
 84→  it("observer creates an inconclusive observation when external signals are unavailable", async () => {
 85→    const { baseUrl, surreal } = getRuntime();
 86→
 87→    // Given a workspace with a task that has no linked PR or external integration
 88→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "skeleton-degrade");
 89→
 90→    // And a task with no external verification signals (no PR URL, no CI link)
 91→    const taskId = `task-${crypto.randomUUID()}`;
 92→    const taskRecord = await import("surrealdb").then(({ RecordId }) => new RecordId("task", taskId));
 93→    const workspaceRecord = await import("surrealdb").then(({ RecordId }) => new RecordId("workspace", workspaceId));
 94→
 95→    await surreal.query(`CREATE $task CONTENT $content;`, {
 96→      task: taskRecord,
 97→      content: {
 98→        title: "Update documentation for API endpoints",
 99→        description: "Refresh the API docs to match current implementation",
100→        status: "in_progress",
101→        workspace: workspaceRecord,
102→        created_at: new Date(),
103→        updated_at: new Date(),
104→      },
105→    });
106→
107→    // When the task is marked as completed
108→    await triggerTaskCompletion(surreal, taskId);
109→
110→    // Then the Observer still creates an observation (does not block or crash)
111→    const observations = await waitForObservation(surreal, "task", taskId, 30_000);
112→
113→    expect(observations.length).toBeGreaterThanOrEqual(1);
114→
115→    const obs = observations[0];
116→    // And the observation is informational (not a conflict, since nothing could be verified)
117→    expect(obs.source_agent).toBe("observer_agent");
118→    expect(obs.severity).toBe("info");
119→    // And the task status remains completed (observer did not revert it)
120→    const taskRows = (await surreal.query(
121→      `SELECT status FROM $task;`,
122→      { task: taskRecord },
123→    )) as Array<Array<{ status: string }>>;
124→    expect(taskRows[0]?.[0]?.status).toBe("completed");
125→  }, 120_000);
126→});
