const { Surreal, RecordId } = require("surrealdb");

async function test() {
  const db = new Surreal();
  await db.connect(process.env.SURREAL_URL || "ws://127.0.0.1:8000/rpc");
  await db.signin({ username: "root", password: "root" });
  await db.use({ namespace: "test_debug_observes", database: "test_debug_observes" });

  // Apply schema
  const fs = require("fs");
  const schema = fs.readFileSync("schema/surreal-schema.surql", "utf-8");
  await db.query(schema);

  // Create observation and intent
  const obsRec = new RecordId("observation", "obs1");
  const intRec = new RecordId("intent", "int1");
  const wsRec = new RecordId("workspace", "ws1");

  await db.query("CREATE $ws CONTENT { name: \"test\", created_at: time::now() };", { ws: wsRec });

  // Create a trace first (required for intent)
  const traceRec = new RecordId("trace", "tr1");
  const identRec = new RecordId("identity", "id1");
  await db.query("CREATE $trace CONTENT { type: \"test\", actor: $actor, workspace: $ws, created_at: time::now() };", { trace: traceRec, actor: identRec, ws: wsRec });

  await db.query("CREATE $intent CONTENT { goal: \"test\", reasoning: \"test\", status: \"completed\", priority: 50, action_spec: { provider: \"test\", action: \"test\" }, trace_id: $trace, requester: $req, workspace: $ws, evaluation: { decision: \"APPROVE\", risk_score: 10, reason: \"ok\", evaluated_at: time::now(), policy_only: false }, created_at: time::now() };", { intent: intRec, trace: traceRec, req: identRec, ws: wsRec });

  await db.query("CREATE $obs CONTENT { text: \"test\", severity: \"info\", status: \"open\", source_agent: \"observer_agent\", workspace: $ws, created_at: time::now() };", { obs: obsRec, ws: wsRec });

  await db.query("RELATE $obs->observes->$target SET added_at = time::now();", { obs: obsRec, target: intRec });

  const result = await db.query("SELECT ->observes->intent FROM $obs;", { obs: obsRec });
  console.log("Result:", JSON.stringify(result, null, 2));

  // Check INFO FOR TABLE
  const info = await db.query("INFO FOR TABLE observes;");
  console.log("Table info:", JSON.stringify(info, null, 2));

  // Cleanup
  await db.query("REMOVE NAMESPACE test_debug_observes;");
  await db.close();
}
test().catch(e => console.error(e));
