122→/**
123→ * Wires all 5 SurrealQL EVENTs for the observer agent.
124→ * Events POST to the test server's observe endpoint.
125→ *
126→ * Must be called in beforeAll after the test server has booted.
127→ */
128→export async function wireObserverEvents(
129→  surreal: Surreal,
130→  port: number,
131→): Promise<void> {
132→  const candidateHosts = process.env.OBSERVER_CALLBACK_HOST?.trim()
133→    ? [process.env.OBSERVER_CALLBACK_HOST.trim()]
134→    : ["127.0.0.1", "host.docker.internal"];
135→
136→  let baseUrl: string | undefined;
137→  let lastError = "";
138→
139→  for (const host of candidateHosts) {
140→    const candidateBaseUrl = `http://${host}:${port}`;
141→    try {
142→      await surreal.query(`RETURN http::head($url);`, {
143→        url: `${candidateBaseUrl}/healthz`,
144→      });
145→      baseUrl = candidateBaseUrl;
146→      break;
147→    } catch (error) {
148→      lastError = error instanceof Error ? error.message : String(error);
149→    }
150→  }
151→
152→  if (!baseUrl) {
153→    throw new Error(
154→      `Unable to reach acceptance server from SurrealDB for observer callback. ` +
155→      `Tried hosts: ${candidateHosts.join(", ")} on port ${port}. ` +
156→      `Last error: ${lastError}`,
157→    );
158→  }
159→
160→  // EVENT 1: task_completed — fires when task status transitions to completed/done
161→  await surreal.query(`
162→    DEFINE EVENT OVERWRITE task_completed ON task
163→      ASYNC
164→      RETRY 3
165→      WHEN ($before.status != "completed" AND $before.status != "done")
166→        AND ($after.status = "completed" OR $after.status = "done")
167→      THEN {
168→        http::post("${baseUrl}/api/observe/task/" + <string> meta::id($after.id), $after)
169→      };
170→  `);
171→
172→  // EVENT 2: intent_completed — fires when intent status transitions to completed/failed
173→  await surreal.query(`
174→    DEFINE EVENT OVERWRITE intent_completed ON intent
175→      ASYNC
176→      RETRY 3
177→      WHEN ($before.status != "completed" AND $before.status != "failed")
178→        AND ($after.status = "completed" OR $after.status = "failed")
179→      THEN {
180→        http::post("${baseUrl}/api/observe/intent/" + <string> meta::id($after.id), $after)
181→      };
182→  `);
183→
184→  // EVENT 3: commit_created — fires when a new git_commit record is created
185→  await surreal.query(`
186→    DEFINE EVENT OVERWRITE commit_created ON git_commit
187→      ASYNC
188→      RETRY 3
189→      WHEN $event = "CREATE"
190→      THEN {
191→        http::post("${baseUrl}/api/observe/git_commit/" + <string> meta::id($after.id), $after)
192→      };
193→  `);
194→
195→  // EVENT 4: decision_confirmed — fires when decision status changes to confirmed/superseded
196→  await surreal.query(`
197→    DEFINE EVENT OVERWRITE decision_confirmed ON decision
198→      ASYNC
199→      RETRY 3
200→      WHEN $before.status != $after.status
201→        AND ($after.status = "confirmed" OR $after.status = "superseded")
202→      THEN {
203→        http::post("${baseUrl}/api/observe/decision/" + <string> meta::id($after.id), $after)
204→      };
205→  `);
206→
207→  // EVENT 5: observation_peer_review — fires when non-observer observation is created
208→  await surreal.query(`
209→    DEFINE EVENT OVERWRITE observation_peer_review ON observation
210→      ASYNC
211→      RETRY 3
212→      WHEN $event = "CREATE" AND $after.source_agent != "observer_agent"
213→      THEN {
214→        http::post("${baseUrl}/api/observe/observation/" + <string> meta::id($after.id), $after)
215→      };
216→  `);
217→}
