361→export async function createObservationByAgent(
362→  surreal: Surreal,
363→  workspaceId: string,
364→  sourceAgent: string,
365→  opts: {
366→    text: string;
367→    severity: ObservationSeverity;
368→    observationType?: ObservationType;
369→    targetTable?: string;
370→    targetId?: string;
