485→/**
486→ * Polls for an observation linked to a given entity via the observes edge.
487→ * Returns when at least one observation is found, or throws on timeout.
488→ */
489→export async function waitForObservation(
490→  surreal: Surreal,
491→  entityTable: string,
492→  entityId: string,
493→  timeoutMs = 15_000,
494→): Promise<ObservationRecord[]> {
495→  const start = Date.now();
496→
497→  while (Date.now() - start < timeoutMs) {
498→    const observations = await getObservationsForEntity(surreal, entityTable, entityId);
499→    if (observations.length > 0) {
500→      return observations;
501→    }
502→    await Bun.sleep(250);
503→  }
504→
505→  throw new Error(
506→    `No observation found for ${entityTable}:${entityId} within ${timeoutMs}ms`,
507→  );
508→}
