557→      `SELECT * FROM observation WHERE workspace = $ws AND source_agent = $agent ORDER BY created_at DESC;`,
558→      { ws: workspaceRecord, agent: sourceAgent },
559→    )) as Array<ObservationRecord[]>;
560→    return rows[0] ?? [];
