587→/**
588→ * Creates a simple mock HTTP server that responds to GitHub-like API paths.
589→ * Returns a cleanup function to stop the server.
590→ */
591→export function createMockGitHubServer(
592→  responses: MockGitHubResponse[],
593→): { url: string; stop: () => void } {
594→  const responseMap = new Map<string, { status: number; body: unknown }>();
595→  for (const r of responses) {
596→    responseMap.set(r.path, { status: r.status, body: r.body });
597→  }
598→
599→  const server = Bun.serve({
600→    port: 0,
601→    fetch(req) {
602→      const url = new URL(req.url);
603→      const match = responseMap.get(url.pathname);
604→      if (match) {
605→        return new Response(JSON.stringify(match.body), {
606→          status: match.status,
607→          headers: { "Content-Type": "application/json" },
608→        });
609→      }
610→      return new Response(JSON.stringify({ message: "Not Found" }), { status: 404 });
611→    },
612→  });
613→
614→  return {
615→    url: `http://127.0.0.1:${server.port}`,
616→    stop: () => server.stop(true),
617→  };
618→}
