620→/**
621→ * Creates a test workspace and identity for observer tests.
622→ * Returns workspace ID, identity ID, and the test user.
623→ */
624→export async function setupObserverWorkspace(
625→  baseUrl: string,
626→  surreal: Surreal,
627→  suffix: string,
628→): Promise<{
629→  user: TestUser;
630→  workspaceId: string;
631→  identityId: string;
632→}> {
633→  const { createTestUser, createTestWorkspace } = await import(
634→    "../coding-agent-orchestrator/orchestrator-test-kit"
635→  );
636→
637→  const user = await createTestUser(baseUrl, suffix);
638→  const workspace = await createTestWorkspace(baseUrl, user);
639→
640→  // Create an agent identity in this workspace
641→  const identityId = `id-${crypto.randomUUID()}`;
642→  const identityRecord = new RecordId("identity", identityId);
643→  const workspaceRecord = new RecordId("workspace", workspace.workspaceId);
644→
645→  await surreal.query(`CREATE $identity CONTENT $content;`, {
646→    identity: identityRecord,
647→    content: {
648→      name: `Observer Test Agent ${suffix}`,
649→      type: "agent",
650→      identity_status: "active",
651→      workspace: workspaceRecord,
652→      created_at: new Date(),
653→    },
654→  });
655→
656→  return { user, workspaceId: workspace.workspaceId, identityId };
657→}
