219→/**
220→ * Creates a task linked to a source commit in the graph.
221→ * Used as a Given-step precondition for task verification scenarios.
222→ */
223→export async function createTaskWithCommit(
224→  surreal: Surreal,
225→  workspaceId: string,
226→  opts: CreateTaskWithCommitOptions,
227→): Promise<{ taskId: string; commitId: string; sha: string }> {
228→  const taskId = `task-${crypto.randomUUID()}`;
229→  const commitId = `commit-${crypto.randomUUID()}`;
230→  const sha = opts.sha ?? `abc${crypto.randomUUID().replace(/-/g, "").slice(0, 37)}`;
231→  const taskRecord = new RecordId("task", taskId);
232→  const commitRecord = new RecordId("git_commit", commitId);
233→  const workspaceRecord = new RecordId("workspace", workspaceId);
234→
235→  // Create the git_commit record (but NOT via CREATE if we want to avoid triggering commit_created EVENT)
236→  // Use a direct insert approach to seed without firing events
237→  await surreal.query(
238→    `CREATE $commit CONTENT $content;`,
239→    {
240→      commit: commitRecord,
241→      content: {
242→        sha,
243→        repository: opts.repository ?? "org/repo",
244→        message: `feat: ${opts.title}`,
245→        author_name: "test-agent",
246→        workspace: workspaceRecord,
247→        created_at: new Date(),
248→      },
249→    },
250→  );
251→
252→  // Create the task linked to the commit
253→  await surreal.query(
254→    `CREATE $task CONTENT $content;`,
255→    {
256→      task: taskRecord,
257→      content: {
258→        title: opts.title,
259→        description: opts.description ?? "Test task for observer verification",
260→        status: opts.status ?? "in_progress",
261→        source_commit: commitRecord,
262→        workspace: workspaceRecord,
263→        created_at: new Date(),
264→        updated_at: new Date(),
265→      },
266→    },
267→  );
268→
269→  return { taskId, commitId, sha };
270→}
