272→/**
273→ * Creates a git_commit record in the graph.
274→ * Note: if commit_created EVENT is wired, this WILL trigger the observer.
275→ */
276→export async function createGitCommit(
277→  surreal: Surreal,
278→  workspaceId: string,
279→  sha: string,
280→  opts?: CreateGitCommitOptions,
281→): Promise<{ commitId: string }> {
282→  const commitId = `commit-${crypto.randomUUID()}`;
283→  const commitRecord = new RecordId("git_commit", commitId);
284→  const workspaceRecord = new RecordId("workspace", workspaceId);
285→
286→  await surreal.query(
287→    `CREATE $commit CONTENT $content;`,
288→    {
289→      commit: commitRecord,
290→      content: {
291→        sha,
292→        repository: opts?.repository ?? "org/repo",
293→        message: opts?.message ?? "chore: test commit",
294→        author_name: opts?.authorName ?? "test-agent",
