510→/**
511→ * Queries all observations linked to an entity via the observes edge.
512→ */
513→export async function getObservationsForEntity(
514→  surreal: Surreal,
515→  entityTable: string,
516→  entityId: string,
517→): Promise<ObservationRecord[]> {
518→  const entityRecord = new RecordId(entityTable, entityId);
519→  const rows = (await surreal.query(
520→    `SELECT * FROM observation WHERE ->observes->(SELECT id FROM $entity) != [];`,
521→    { entity: entityRecord },
522→  )) as Array<ObservationRecord[]>;
523→
524→  // Fallback: query via reverse traversal
525→  if (!rows[0]?.length) {
526→    const reverseRows = (await surreal.query(
527→      `SELECT <-observes<-observation AS obs FROM $entity;`,
528→      { entity: entityRecord },
529→    )) as Array<Array<{ obs: RecordId[] }>>;
530→
531→    const obsIds = reverseRows[0]?.[0]?.obs ?? [];
532→    if (obsIds.length === 0) return [];
533→
534→    const allObs = (await surreal.query(
535→      `SELECT * FROM observation WHERE id IN $ids;`,
536→      { ids: obsIds },
537→    )) as Array<ObservationRecord[]>;
538→
539→    return allObs[0] ?? [];
540→  }
541→
542→  return rows[0] ?? [];
543→}
