479→export async function startServer(): Promise<void> {
480→  const config = loadServerConfig();
481→  const runtime = await createRuntimeDependencies(config);
482→  await ensureDefaultWorkspaceProjectScope(runtime.surreal);
483→
484→  const deps: ServerDependencies = {
485→    config,
486→    surreal: runtime.surreal,
487→    analyticsSurreal: runtime.analyticsSurreal,
488→    auth: runtime.auth,
489→    chatAgentModel: runtime.chatAgentModel,
490→    extractionModel: runtime.extractionModel,
491→    pmAgentModel: runtime.pmAgentModel,
492→    analyticsAgentModel: runtime.analyticsAgentModel,
493→    embeddingModel: runtime.embeddingModel,
494→    sse: createSseRegistry(),
495→    inflight: createInflightTracker(),
496→    asSigningKey: runtime.asSigningKey,
497→    nonceCache: createNonceCache(),
498→  };
499→
500→  const server = createBrainServer(deps);
501→
502→  // Recover intents stuck in pending_veto with expired windows (fire-and-forget)
503→  const vetoManager = createVetoManager();
504→  deps.inflight.track(
505→    vetoManager.recoverExpiredWindows({
506→      updateStatus: (intentId, status) => updateIntentStatus(deps.surreal, intentId, status),
507→      emitVetoEvent: (event) => logInfo("intent.veto.recovery", "Recovered expired veto window", { event }),
508→      queryExpiredVetoIntents: () => queryExpiredVetoIntents(deps.surreal),
509→    }).catch((err) => {
510→      logError("intent.veto.recovery", "Failed to recover expired veto windows", err);
511→    }),
512→  );
513→
514→  logInfo("server.started", "Brain app server started", {
515→    port: server.port,
516→    host: "127.0.0.1",
517→    chatAgentModelId: config.chatAgentModelId,
518→    extractionModelId: config.extractionModelId,
519→    pmAgentModelId: config.pmAgentModelId,
520→    embeddingModelId: config.embeddingModelId,
521→    embeddingDimension: config.embeddingDimension,
522→    extractionStoreThreshold: config.extractionStoreThreshold,
523→    extractionDisplayThreshold: config.extractionDisplayThreshold,
524→    surrealTransport: config.surrealUrl.startsWith("wss://")
525→      ? "wss"
526→      : config.surrealUrl.startsWith("ws://")
527→        ? "ws"
528→        : config.surrealUrl.startsWith("https://")
529→          ? "https"
530→          : "http",
531→    surrealNamespace: config.surrealNamespace,
532→    surrealDatabase: config.surrealDatabase,
533→    openRouterReasoningEnabled: config.openRouterReasoning !== undefined,
534→  });
535→}
