/**
 * External signal gathering for the observer verification pipeline.
 *
 * Driven port: functions that fetch external CI/GitHub status for commits.
 * Pure types + effect-boundary functions kept separate from domain logic.
 */
import type { Surreal } from "surrealdb";
import { RecordId } from "surrealdb";
import { logError, logInfo } from "../http/observability";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type CiStatus = "success" | "failure" | "pending" | "unknown";

export type ExternalSignal = {
  sha: string;
  repository: string;
  ciStatus: CiStatus;
  source: string;
};

export type GatherSignalsResult = {
  signals: ExternalSignal[];
  hasCommits: boolean;
};

type CommitRecord = {
  id: RecordId<"git_commit", string>;
  sha: string;
  repository?: string;
};

// ---------------------------------------------------------------------------
// Gather linked commits for a task
// ---------------------------------------------------------------------------

export async function gatherLinkedCommits(
  surreal: Surreal,
  taskId: string,
): Promise<CommitRecord[]> {
  const taskRecord = new RecordId("task", taskId);

  // Check source_commit field on the task
  const [taskRows] = await surreal.query<
    [Array<{ source_commit?: RecordId<"git_commit", string> }>]
  >(
    `SELECT source_commit FROM $task;`,
    { task: taskRecord },
  );

  const sourceCommit = taskRows?.[0]?.source_commit;
  if (!sourceCommit) return [];

  // Fetch the commit record
  const [commitRows] = await surreal.query<[CommitRecord[]]>(
    `SELECT id, sha, repository FROM $commit;`,
    { commit: sourceCommit },
  );

  return commitRows ?? [];
}

// ---------------------------------------------------------------------------
// Check CI status for a commit (GitHub API)
// ---------------------------------------------------------------------------

export async function checkCiStatus(
  commit: CommitRecord,
): Promise<ExternalSignal> {
  const sha = commit.sha;
  const repository = commit.repository ?? "";

  if (!repository) {
    return { sha, repository, ciStatus: "unknown", source: "none" };
  }

  // Attempt GitHub commit status API
  const githubApiUrl = `https://api.github.com/repos/${repository}/commits/${sha}/status`;

  try {
    const response = await fetch(githubApiUrl, {
      headers: {
        Accept: "application/vnd.github.v3+json",
        ...(process.env.GITHUB_TOKEN
          ? { Authorization: `Bearer ${process.env.GITHUB_TOKEN}` }
          : {}),
      },
      signal: AbortSignal.timeout(10_000),
    });

    if (!response.ok) {
      logInfo("observer.ci_check.http_error", "GitHub API returned non-OK", {
        status: response.status,
        sha,
        repository,
      });
      return { sha, repository, ciStatus: "unknown", source: "github" };
    }

    const data = (await response.json()) as { state?: string };
    const ciStatus = mapGitHubState(data.state);

    return { sha, repository, ciStatus, source: "github" };
  } catch (error) {
    logError("observer.ci_check.failed", "Failed to check CI status", error);
    return { sha, repository, ciStatus: "unknown", source: "github" };
  }
}

function mapGitHubState(state?: string): CiStatus {
  switch (state) {
    case "success":
      return "success";
    case "failure":
    case "error":
      return "failure";
    case "pending":
      return "pending";
    default:
      return "unknown";
  }
}

// ---------------------------------------------------------------------------
// Gather all external signals for a task
// ---------------------------------------------------------------------------

export async function gatherTaskSignals(
  surreal: Surreal,
  taskId: string,
): Promise<GatherSignalsResult> {
  const commits = await gatherLinkedCommits(surreal, taskId);

  if (commits.length === 0) {
    return { signals: [], hasCommits: false };
  }

  const signals = await Promise.all(commits.map(checkCiStatus));
  return { signals, hasCommits: true };
}

/**
 * Verification pipeline: pure core functions for claim-vs-reality comparison.
 *
 * Pipeline: receiveEvent -> gatherSignals -> compareClaimVsReality -> createObservation
 *
 * All functions in this module are pure (no IO). The effect shell lives in observer-route.ts.
 */

import type { ExternalSignal, GatherSignalsResult } from "./external-signals";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type Verdict = "match" | "mismatch" | "inconclusive";

export type VerificationResult = {
  verdict: Verdict;
  severity: "info" | "warning" | "conflict";
  verified: boolean;
  text: string;
  source?: string;
};

// ---------------------------------------------------------------------------
// Pure comparison: claim vs reality for task completion
// ---------------------------------------------------------------------------

export function compareTaskCompletion(
  signalsResult: GatherSignalsResult,
): VerificationResult {
  // No commits linked -> inconclusive
  if (!signalsResult.hasCommits || signalsResult.signals.length === 0) {
    return {
      verdict: "inconclusive",
      severity: "info",
      verified: false,
      text: "Unable to verify task completion: no external signals (commits or CI) found for this task.",
    };
  }

  // Check CI status across all signals
  const ciSignals = signalsResult.signals.filter(
    (signal) => signal.ciStatus !== "unknown",
  );

  // All signals unknown -> inconclusive
  if (ciSignals.length === 0) {
    return {
      verdict: "inconclusive",
      severity: "info",
      verified: false,
      text: "Unable to verify task completion: CI status unavailable for linked commits.",
      source: signalsResult.signals[0]?.source,
    };
  }

  // Any failing CI -> mismatch
  const failingSignals = ciSignals.filter(
    (signal) => signal.ciStatus === "failure",
  );

  if (failingSignals.length > 0) {
    const failingShas = failingSignals.map((s) => s.sha.slice(0, 8)).join(", ");
    return {
      verdict: "mismatch",
      severity: "conflict",
      verified: false,
      text: `Task marked as completed but CI is failing for commit(s): ${failingShas}. Claim does not match reality.`,
      source: failingSignals[0]?.source,
    };
  }

  // Any pending CI -> inconclusive (not verified yet)
  const pendingSignals = ciSignals.filter(
    (signal) => signal.ciStatus === "pending",
  );

  if (pendingSignals.length > 0) {
    return {
      verdict: "inconclusive",
      severity: "info",
      verified: false,
      text: "Task completion verification pending: CI checks still running.",
      source: pendingSignals[0]?.source,
    };
  }

  // All passing -> match
  const source = ciSignals[0]?.source;
  return {
    verdict: "match",
    severity: "info",
    verified: true,
    text: "Task completion verified: all linked CI checks are passing.",
    source,
  };
}

/**
 * Observer HTTP route: POST /api/observe/:table/:id
 *
 * Effect shell that wires the verification pipeline to SurrealDB.
 * Called by SurrealDB EVENTs when entity state transitions occur.
 *
 * Pipeline: receiveEvent -> gatherSignals -> compareClaimVsReality -> persistObservation
 */

import { RecordId } from "surrealdb";
import { jsonResponse } from "../http/response";
import { logError, logInfo } from "../http/observability";
import { createObservation } from "../observation/queries";
import { gatherTaskSignals } from "./external-signals";
import { compareTaskCompletion } from "./verification-pipeline";
import type { ServerDependencies } from "../runtime/types";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type SupportedTable = "task" | "intent" | "git_commit" | "decision" | "observation";

const SUPPORTED_TABLES = new Set<string>([
  "task",
  "intent",
  "git_commit",
  "decision",
  "observation",
]);

// ---------------------------------------------------------------------------
// Route handler factory
// ---------------------------------------------------------------------------

export function createObserverRouteHandler(deps: ServerDependencies) {
  return async (table: string, id: string, request: Request): Promise<Response> => {
    if (!SUPPORTED_TABLES.has(table)) {
      return jsonResponse({ error: "unsupported_table", table }, 400);
    }

    const supportedTable = table as SupportedTable;

    try {
      // Parse the EVENT body (the record itself, posted by SurrealDB EVENT)
      const body = await request.json().catch(() => undefined);

      logInfo("observer.event.received", "Observer event received", {
        table: supportedTable,
        id,
      });

      // Dispatch to the appropriate verification pipeline
      switch (supportedTable) {
        case "task":
          await handleTaskVerification(deps, id, body);
          break;

        case "intent":
        case "git_commit":
        case "decision":
        case "observation":
          // Placeholder: future milestones will implement these
          logInfo("observer.event.skipped", "Observer event type not yet implemented", {
            table: supportedTable,
            id,
          });
          break;
      }

      return jsonResponse({ status: "ok" }, 200);
    } catch (error) {
      logError("observer.event.error", "Observer event processing failed", error);
      // Return 200 to prevent SurrealDB EVENT retries for non-transient errors
      return jsonResponse({ status: "error", message: "processing failed" }, 200);
    }
  };
}

// ---------------------------------------------------------------------------
// Task verification pipeline (effect shell)
// ---------------------------------------------------------------------------

async function handleTaskVerification(
  deps: ServerDependencies,
  taskId: string,
  body?: Record<string, unknown>,
): Promise<void> {
  const { surreal } = deps;

  // Resolve workspace from the task record body or by querying
  const workspaceId = await resolveWorkspaceId(surreal, "task", taskId, body);
  if (!workspaceId) {
    logError("observer.task.no_workspace", "Cannot determine workspace for task", { taskId });
    return;
  }

  const workspaceRecord = new RecordId("workspace", workspaceId);
  const taskRecord = new RecordId("task", taskId);

  // Pipeline: gather signals -> compare -> persist
  const signalsResult = await gatherTaskSignals(surreal, taskId);
  const verificationResult = compareTaskCompletion(signalsResult);

  const now = new Date();

  await createObservation({
    surreal,
    workspaceRecord,
    text: verificationResult.text,
    severity: verificationResult.severity,
    sourceAgent: "observer_agent",
    observationType: "validation",
    now,
    relatedRecord: taskRecord,
  });

  // Update the observation with verified and source fields
  // (createObservation doesn't support these extra fields directly)
  const [observations] = await surreal.query<
    [Array<{ id: RecordId<"observation", string> }>]
  >(
    `SELECT id FROM observation WHERE source_agent = "observer_agent" AND workspace = $ws ORDER BY created_at DESC LIMIT 1;`,
    { ws: workspaceRecord },
  );

  const observationId = observations?.[0]?.id;
  if (observationId) {
    await surreal.query(
      `UPDATE $obs SET verified = $verified, source = $source;`,
      {
        obs: observationId,
        verified: verificationResult.verified,
        source: verificationResult.source ?? "none",
      },
    );
  }

  logInfo("observer.task.verified", "Task verification complete", {
    taskId,
    verdict: verificationResult.verdict,
    severity: verificationResult.severity,
    verified: verificationResult.verified,
  });
}

// ---------------------------------------------------------------------------
// Workspace resolution
// ---------------------------------------------------------------------------

async function resolveWorkspaceId(
  surreal: import("surrealdb").Surreal,
  table: string,
  id: string,
  body?: Record<string, unknown>,
): Promise<string | undefined> {
  // Try body first (SurrealDB EVENT passes the full record)
  if (body?.workspace) {
    const ws = body.workspace;
    // Could be a RecordId-like object or a string
    if (typeof ws === "string") {
      // Handle "workspace:uuid" format
      return ws.includes(":") ? ws.split(":")[1] : ws;
    }
    if (typeof ws === "object" && ws !== null) {
      const wsObj = ws as { id?: string | { String?: string } };
      if (typeof wsObj.id === "string") return wsObj.id;
      if (wsObj.id && typeof (wsObj.id as { String?: string }).String === "string") {
        return (wsObj.id as { String: string }).String;
      }
    }
  }

  // Fallback: query the DB
  const record = new RecordId(table, id);
  const [rows] = await surreal.query<
    [Array<{ workspace: RecordId<"workspace", string> }>]
  >(
    `SELECT workspace FROM $record;`,
    { record },
  );

  const wsRecord = rows?.[0]?.workspace;
  return wsRecord ? (wsRecord.id as string) : undefined;
}

