  1→/**
  2→ * External signal gathering for the observer verification pipeline.
  3→ *
  4→ * Driven port: functions that fetch external CI/GitHub status for commits.
  5→ * Pure types + effect-boundary functions kept separate from domain logic.
  6→ */
  7→import type { Surreal } from "surrealdb";
  8→import { RecordId } from "surrealdb";
  9→import { logError, logInfo } from "../http/observability";
 10→
 11→// ---------------------------------------------------------------------------
 12→// Types
 13→// ---------------------------------------------------------------------------
 14→
 15→export type CiStatus = "success" | "failure" | "pending" | "unknown";
 16→
 17→export type ExternalSignal = {
 18→  sha: string;
 19→  repository: string;
 20→  ciStatus: CiStatus;
 21→  source: string;
 22→};
 23→
 24→export type GatherSignalsResult = {
 25→  signals: ExternalSignal[];
 26→  hasCommits: boolean;
 27→};
 28→
 29→type CommitRecord = {
 30→  id: RecordId<"git_commit", string>;
 31→  sha: string;
 32→  repository?: string;
 33→};
 34→
 35→// ---------------------------------------------------------------------------
 36→// Gather linked commits for a task
 37→// ---------------------------------------------------------------------------
 38→
 39→export async function gatherLinkedCommits(
 40→  surreal: Surreal,
 41→  taskId: string,
 42→): Promise<CommitRecord[]> {
 43→  const taskRecord = new RecordId("task", taskId);
 44→
 45→  // Check source_commit field on the task
 46→  const [taskRows] = await surreal.query<
 47→    [Array<{ source_commit?: RecordId<"git_commit", string> }>]
 48→  >(
 49→    `SELECT source_commit FROM $task;`,
 50→    { task: taskRecord },
 51→  );
 52→
 53→  const sourceCommit = taskRows?.[0]?.source_commit;
 54→  if (!sourceCommit) return [];
 55→
 56→  // Fetch the commit record
 57→  const [commitRows] = await surreal.query<[CommitRecord[]]>(
 58→    `SELECT id, sha, repository FROM $commit;`,
 59→    { commit: sourceCommit },
 60→  );
 61→
 62→  return commitRows ?? [];
 63→}
 64→
 65→// ---------------------------------------------------------------------------
 66→// Check CI status for a commit (GitHub API)
 67→// ---------------------------------------------------------------------------
 68→
 69→export async function checkCiStatus(
 70→  commit: CommitRecord,
 71→): Promise<ExternalSignal> {
 72→  const sha = commit.sha;
 73→  const repository = commit.repository ?? "";
 74→
 75→  if (!repository) {
 76→    return { sha, repository, ciStatus: "unknown", source: "none" };
 77→  }
 78→
 79→  // Attempt GitHub commit status API
 80→  const githubApiUrl = `https://api.github.com/repos/${repository}/commits/${sha}/status`;
 81→
 82→  try {
 83→    const response = await fetch(githubApiUrl, {
 84→      headers: {
 85→        Accept: "application/vnd.github.v3+json",
 86→        ...(process.env.GITHUB_TOKEN
 87→          ? { Authorization: `Bearer ${process.env.GITHUB_TOKEN}` }
 88→          : {}),
 89→      },
 90→      signal: AbortSignal.timeout(10_000),
 91→    });
 92→
 93→    if (!response.ok) {
 94→      logInfo("observer.ci_check.http_error", "GitHub API returned non-OK", {
 95→        status: response.status,
 96→        sha,
 97→        repository,
 98→      });
 99→      return { sha, repository, ciStatus: "unknown", source: "github" };
100→    }
101→
102→    const data = (await response.json()) as { state?: string };
103→    const ciStatus = mapGitHubState(data.state);
104→
105→    return { sha, repository, ciStatus, source: "github" };
106→  } catch (error) {
107→    logError("observer.ci_check.failed", "Failed to check CI status", error);
108→    return { sha, repository, ciStatus: "unknown", source: "github" };
109→  }
110→}
111→
112→function mapGitHubState(state?: string): CiStatus {
113→  switch (state) {
114→    case "success":
115→      return "success";
116→    case "failure":
117→    case "error":
118→      return "failure";
119→    case "pending":
120→      return "pending";
121→    default:
122→      return "unknown";
123→  }
124→}
125→
126→// ---------------------------------------------------------------------------
127→// Gather all external signals for a task
128→// ---------------------------------------------------------------------------
129→
130→export async function gatherTaskSignals(
131→  surreal: Surreal,
132→  taskId: string,
133→): Promise<GatherSignalsResult> {
134→  const commits = await gatherLinkedCommits(surreal, taskId);
135→
136→  if (commits.length === 0) {
137→    return { signals: [], hasCommits: false };
138→  }
139→
140→  const signals = await Promise.all(commits.map(checkCiStatus));
141→  return { signals, hasCommits: true };
142→}
143→

