  1→/**
  2→ * Observer HTTP route: POST /api/observe/:table/:id
  3→ *
  4→ * Effect shell that wires the verification pipeline to SurrealDB.
  5→ * Called by SurrealDB EVENTs when entity state transitions occur.
  6→ *
  7→ * Pipeline: receiveEvent -> gatherSignals -> compareClaimVsReality -> persistObservation
  8→ */
  9→
 10→import { RecordId } from "surrealdb";
 11→import { jsonResponse } from "../http/response";
 12→import { logError, logInfo } from "../http/observability";
 13→import { createObservation } from "../observation/queries";
 14→import { gatherTaskSignals } from "./external-signals";
 15→import { compareTaskCompletion } from "./verification-pipeline";
 16→import type { ServerDependencies } from "../runtime/types";
 17→
 18→// ---------------------------------------------------------------------------
 19→// Types
 20→// ---------------------------------------------------------------------------
 21→
 22→type SupportedTable = "task" | "intent" | "git_commit" | "decision" | "observation";
 23→
 24→const SUPPORTED_TABLES = new Set<string>([
 25→  "task",
 26→  "intent",
 27→  "git_commit",
 28→  "decision",
 29→  "observation",
 30→]);
 31→
 32→// ---------------------------------------------------------------------------
 33→// Route handler factory
 34→// ---------------------------------------------------------------------------
 35→
 36→export function createObserverRouteHandler(deps: ServerDependencies) {
 37→  return async (table: string, id: string, request: Request): Promise<Response> => {
 38→    if (!SUPPORTED_TABLES.has(table)) {
 39→      return jsonResponse({ error: "unsupported_table", table }, 400);
 40→    }
 41→
 42→    const supportedTable = table as SupportedTable;
 43→
 44→    try {
 45→      // Parse the EVENT body (the record itself, posted by SurrealDB EVENT)
 46→      const body = await request.json().catch(() => undefined);
 47→
 48→      logInfo("observer.event.received", "Observer event received", {
 49→        table: supportedTable,
 50→        id,
 51→      });
 52→
 53→      // Dispatch to the appropriate verification pipeline
 54→      switch (supportedTable) {
 55→        case "task":
 56→          await handleTaskVerification(deps, id, body);
 57→          break;
 58→
 59→        case "intent":
 60→        case "git_commit":
 61→        case "decision":
 62→        case "observation":
 63→          // Placeholder: future milestones will implement these
 64→          logInfo("observer.event.skipped", "Observer event type not yet implemented", {
 65→            table: supportedTable,
 66→            id,
 67→          });
 68→          break;
 69→      }
 70→
 71→      return jsonResponse({ status: "ok" }, 200);
 72→    } catch (error) {
 73→      logError("observer.event.error", "Observer event processing failed", error);
 74→      // Return 200 to prevent SurrealDB EVENT retries for non-transient errors
 75→      return jsonResponse({ status: "error", message: "processing failed" }, 200);
 76→    }
 77→  };
 78→}
 79→
 80→// ---------------------------------------------------------------------------
 81→// Task verification pipeline (effect shell)
 82→// ---------------------------------------------------------------------------
 83→
 84→async function handleTaskVerification(
 85→  deps: ServerDependencies,
 86→  taskId: string,
 87→  body?: Record<string, unknown>,
 88→): Promise<void> {
 89→  const { surreal } = deps;
 90→
 91→  // Resolve workspace from the task record body or by querying
 92→  const workspaceId = await resolveWorkspaceId(surreal, "task", taskId, body);
 93→  if (!workspaceId) {
 94→    logError("observer.task.no_workspace", "Cannot determine workspace for task", { taskId });
 95→    return;
 96→  }
 97→
 98→  const workspaceRecord = new RecordId("workspace", workspaceId);
 99→  const taskRecord = new RecordId("task", taskId);
100→
101→  // Pipeline: gather signals -> compare -> persist
102→  const signalsResult = await gatherTaskSignals(surreal, taskId);
103→  const verificationResult = compareTaskCompletion(signalsResult);
104→
105→  const now = new Date();
106→
107→  await createObservation({
108→    surreal,
109→    workspaceRecord,
110→    text: verificationResult.text,
111→    severity: verificationResult.severity,
112→    sourceAgent: "observer_agent",
113→    observationType: "validation",
114→    now,
115→    relatedRecord: taskRecord,
116→  });
117→
118→  // Update the observation with verified and source fields
119→  // (createObservation doesn't support these extra fields directly)
120→  const [observations] = await surreal.query<
121→    [Array<{ id: RecordId<"observation", string> }>]
122→  >(
123→    `SELECT id FROM observation WHERE source_agent = "observer_agent" AND workspace = $ws ORDER BY created_at DESC LIMIT 1;`,
124→    { ws: workspaceRecord },
125→  );
126→
127→  const observationId = observations?.[0]?.id;
128→  if (observationId) {
129→    await surreal.query(
130→      `UPDATE $obs SET verified = $verified, source = $source;`,
131→      {
132→        obs: observationId,
133→        verified: verificationResult.verified,
134→        source: verificationResult.source ?? "none",
135→      },
136→    );
137→  }
138→
139→  logInfo("observer.task.verified", "Task verification complete", {
140→    taskId,
141→    verdict: verificationResult.verdict,
142→    severity: verificationResult.severity,
143→    verified: verificationResult.verified,
144→  });
145→}
146→
147→// ---------------------------------------------------------------------------
148→// Workspace resolution
149→// ---------------------------------------------------------------------------
150→
151→async function resolveWorkspaceId(
152→  surreal: import("surrealdb").Surreal,
153→  table: string,
154→  id: string,
155→  body?: Record<string, unknown>,
156→): Promise<string | undefined> {
157→  // Try body first (SurrealDB EVENT passes the full record)
158→  if (body?.workspace) {
159→    const ws = body.workspace;
160→    // Could be a RecordId-like object or a string
161→    if (typeof ws === "string") {
162→      // Handle "workspace:uuid" format
163→      return ws.includes(":") ? ws.split(":")[1] : ws;
164→    }
165→    if (typeof ws === "object" && ws !== null) {
166→      const wsObj = ws as { id?: string | { String?: string } };
167→      if (typeof wsObj.id === "string") return wsObj.id;
168→      if (wsObj.id && typeof (wsObj.id as { String?: string }).String === "string") {
169→        return (wsObj.id as { String: string }).String;
170→      }
171→    }
172→  }
173→
174→  // Fallback: query the DB
175→  const record = new RecordId(table, id);
176→  const [rows] = await surreal.query<
177→    [Array<{ workspace: RecordId<"workspace", string> }>]
178→  >(
179→    `SELECT workspace FROM $record;`,
180→    { record },
181→  );
182→
183→  const wsRecord = rows?.[0]?.workspace;
184→  return wsRecord ? (wsRecord.id as string) : undefined;
185→}
186→

