 1→/**
 2→ * Verification pipeline: pure core functions for claim-vs-reality comparison.
 3→ *
 4→ * Pipeline: receiveEvent -> gatherSignals -> compareClaimVsReality -> createObservation
 5→ *
 6→ * All functions in this module are pure (no IO). The effect shell lives in observer-route.ts.
 7→ */
 8→
 9→import type { ExternalSignal, GatherSignalsResult } from "./external-signals";
10→
11→// ---------------------------------------------------------------------------
12→// Types
13→// ---------------------------------------------------------------------------
14→
15→export type Verdict = "match" | "mismatch" | "inconclusive";
16→
17→export type VerificationResult = {
18→  verdict: Verdict;
19→  severity: "info" | "warning" | "conflict";
20→  verified: boolean;
21→  text: string;
22→  source?: string;
23→};
24→
25→// ---------------------------------------------------------------------------
26→// Pure comparison: claim vs reality for task completion
27→// ---------------------------------------------------------------------------
28→
29→export function compareTaskCompletion(
30→  signalsResult: GatherSignalsResult,
31→): VerificationResult {
32→  // No commits linked -> inconclusive
33→  if (!signalsResult.hasCommits || signalsResult.signals.length === 0) {
34→    return {
35→      verdict: "inconclusive",
36→      severity: "info",
37→      verified: false,
38→      text: "Unable to verify task completion: no external signals (commits or CI) found for this task.",
39→    };
40→  }
41→
42→  // Check CI status across all signals
43→  const ciSignals = signalsResult.signals.filter(
44→    (signal) => signal.ciStatus !== "unknown",
45→  );
46→
47→  // All signals unknown -> inconclusive
48→  if (ciSignals.length === 0) {
49→    return {
50→      verdict: "inconclusive",
51→      severity: "info",
52→      verified: false,
53→      text: "Unable to verify task completion: CI status unavailable for linked commits.",
54→      source: signalsResult.signals[0]?.source,
55→    };
56→  }
57→
58→  // Any failing CI -> mismatch
59→  const failingSignals = ciSignals.filter(
60→    (signal) => signal.ciStatus === "failure",
61→  );
62→
63→  if (failingSignals.length > 0) {
64→    const failingShas = failingSignals.map((s) => s.sha.slice(0, 8)).join(", ");
65→    return {
66→      verdict: "mismatch",
67→      severity: "conflict",
68→      verified: false,
69→      text: `Task marked as completed but CI is failing for commit(s): ${failingShas}. Claim does not match reality.`,
70→      source: failingSignals[0]?.source,
71→    };
72→  }
73→
74→  // Any pending CI -> inconclusive (not verified yet)
75→  const pendingSignals = ciSignals.filter(
76→    (signal) => signal.ciStatus === "pending",
77→  );
78→
79→  if (pendingSignals.length > 0) {
80→    return {
81→      verdict: "inconclusive",
82→      severity: "info",
83→      verified: false,
84→      text: "Task completion verification pending: CI checks still running.",
85→      source: pendingSignals[0]?.source,
86→    };
87→  }
88→
89→  // All passing -> match
90→  const source = ciSignals[0]?.source;
91→  return {
92→    verdict: "match",
93→    severity: "info",
94→    verified: true,
95→    text: "Task completion verified: all linked CI checks are passing.",
96→    source,
97→  };
98→}
