 45→describe("Milestone 2: Task Completion Verification (Story 1)", () => {
 46→  // ---------------------------------------------------------------------------
 47→  // S1-1: Task with passing CI -> observation severity info, verified true
 48→  // ---------------------------------------------------------------------------
 49→  it("task linked to passing CI produces a verified observation", async () => {
 50→    const { baseUrl, surreal } = getRuntime();
 51→
 52→    // Given a workspace with a task linked to a commit with passing CI
 53→    const { workspaceId } = await setupObserverWorkspace(baseUrl, surreal, "verify-pass");
 54→    const sha = `abc${crypto.randomUUID().replace(/-/g, "").slice(0, 37)}`;
