512→ */
513→export async function getObservationsForEntity(
514→  surreal: Surreal,
515→  entityTable: string,
516→  entityId: string,
517→): Promise<ObservationRecord[]> {
518→  const entityRecord = new RecordId(entityTable, entityId);
519→
520→  // Query via reverse traversal from the entity through observes edges
521→  const reverseRows = (await surreal.query(
522→    `SELECT <-observes<-observation AS obs FROM $entity;`,
523→    { entity: entityRecord },
524→  )) as Array<Array<{ obs: RecordId[] }>>;
525→
526→  const obsIds = reverseRows[0]?.[0]?.obs ?? [];
527→  if (obsIds.length === 0) return [];
528→
529→  const allObs = (await surreal.query(
530→    `SELECT * FROM observation WHERE id IN $ids;`,
531→    { ids: obsIds },
532→  )) as Array<ObservationRecord[]>;
533→
534→  return allObs[0] ?? [];
