581→ * Returns a cleanup function to stop the server.
582→ */
583→export function createMockGitHubServer(
584→  responses: MockGitHubResponse[],
585→): { url: string; stop: () => void } {
586→  const responseMap = new Map<string, { status: number; body: unknown }>();
587→  for (const r of responses) {
588→    responseMap.set(r.path, { status: r.status, body: r.body });
589→  }
590→
591→  const server = Bun.serve({
592→    port: 0,
593→    fetch(req) {
594→      const url = new URL(req.url);
595→      const match = responseMap.get(url.pathname);
596→      if (match) {
597→        return new Response(JSON.stringify(match.body), {
598→          status: match.status,
599→          headers: { "Content-Type": "application/json" },
600→        });
601→      }
602→      return new Response(JSON.stringify({ message: "Not Found" }), { status: 404 });
603→    },
604→  });
605→
606→  return {
607→    url: `http://127.0.0.1:${server.port}`,
608→    stop: () => server.stop(true),
609→  };
